/// Property map for a single `Function` value in the side-table.
type FnPropMap = Rc<RefCell<HashMap<String, JsValue>>>;
type MonoLoadCache = HashMap<u32, (usize, JsValue)>;
type PolyLoadCache = HashMap<u32, Vec<(usize, JsValue)>>;
type ProtoLoadIcCache = ProtoIcCache;
type StringCache = HashMap<u32, Rc<str>>;
type GlobalIcCache = HashMap<u32, (usize, u64)>;

thread_local! {
    /// The currently-attached debugger for this thread, if any.
    ///
    /// When `Some`, the interpreter checks for breakpoints and step conditions
    /// before each instruction dispatch and calls the appropriate hook methods
    /// on pauses.
    pub(super) static ACTIVE_DEBUGGER: RefCell<Option<Rc<RefCell<Debugger>>>> =
        const { RefCell::new(None) };

    /// Side table mapping `Function` identity (pointer of the inner
    /// `Rc<BytecodeArray>`) to a property map.
    ///
    /// JavaScript functions are objects and can carry ad-hoc properties
    /// (e.g. `assert.sameValue = function(){}`).  Rather than modifying the
    /// [`JsValue::Function`] variant to include a property map (which would
    /// touch dozens of match arms), we store properties in this thread-local
    /// table.  All `Rc` clones of the same `BytecodeArray` share the same
    /// pointer, so property stores through one clone are visible through all
    /// clones.
    static FUNCTION_PROPS: RefCell<HashMap<usize, FnPropMap>> =
        RefCell::new(HashMap::new());

    /// Thread-local string interning table for property key deduplication.
    ///
    /// Property keys that appear in hot loops (e.g. `"length"`, `"prototype"`,
    /// `"constructor"`) are interned so that repeated lookups compare interned
    /// pointer identity instead of full string equality.
    static STRING_TABLE: RefCell<crate::objects::js_string::StringTable> =
        RefCell::new(crate::objects::js_string::StringTable::new());

    /// Thread-local pool of spilled register file buffers.
    /// Avoids repeated heap allocation for large interpreter frames.
    static REGISTER_POOL: RefCell<Vec<Vec<JsValue>>> = const { RefCell::new(Vec::new()) };

    /// Thread-local pool of reusable [`InterpreterFrame`] structs.
    /// Avoids heap allocation for every function call by recycling frames.
    static FRAME_POOL: RefCell<Vec<InterpreterFrame>> = const { RefCell::new(Vec::new()) };
}

thread_local! {
    /// Fast-path flag indicating whether a debugger is attached on this thread.
    ///
    /// Checked on every instruction dispatch before touching the thread-local
    /// `ACTIVE_DEBUGGER` RefCell.  This avoids a TLS+RefCell borrow on every
    /// single instruction when no debugger is present (the common case).
    ///
    /// Must be thread-local (not a global `AtomicBool`) because
    /// `ACTIVE_DEBUGGER` is thread-local: a global flag would let one thread's
    /// `detach_debugger` hide another thread's attached debugger, causing
    /// flaky breakpoint misses in parallel tests.
    static DEBUG_ATTACHED: Cell<bool> = const { Cell::new(false) };

    /// Reference to the current thread's global environment.
    ///
    /// Set at the start of [`Interpreter::run`] so that [`proto_lookup`] can
    /// resolve built-in constructor properties (e.g. `[].constructor === Array`)
    /// without threading the global env through every call site.
    #[allow(clippy::type_complexity)]
    static CURRENT_GLOBALS: RefCell<Option<Rc<RefCell<GlobalEnv>>>> =
        const { RefCell::new(None) };

    /// Per-thread cache of resolved prototype lookups for plain-object receivers.
    ///
    /// The cache key uses receiver pointer identity plus property-key pointer
    /// identity, which keeps hot repeated lookups O(1) for stable object shapes.
    static PROTO_CACHE: RefCell<HashMap<(usize, u64), (JsValue, u8)>> =
        RefCell::new(HashMap::with_capacity(64));

    /// Validation generation for entries stored in [`PROTO_CACHE`].
    static PROTO_CACHE_GENERATIONS: RefCell<HashMap<(usize, u64), u32>> =
        RefCell::new(HashMap::with_capacity(64));

    /// Last observed global prototype-mutation epoch for the thread-local caches.
    static PROTO_CACHE_EPOCH: Cell<u64> = const { Cell::new(0) };

    /// Small cache for built-in Object.prototype resolutions that do not depend
    /// on a specific receiver instance.
    static BUILTIN_METHODS: RefCell<HashMap<&'static str, JsValue>> =
        RefCell::new(HashMap::with_capacity(8));
}

/// Attach a [`Debugger`] to the current thread's interpreter.
///
/// While attached, the interpreter checks for breakpoints and step conditions
/// before each instruction dispatch.  Only one debugger can be attached per
/// thread; calling this again replaces any previously attached debugger.
pub fn attach_debugger(dbg: Rc<RefCell<Debugger>>) {
    ACTIVE_DEBUGGER.with(|d| *d.borrow_mut() = Some(dbg));
    DEBUG_ATTACHED.with(|f| f.set(true));
}

/// Detach the [`Debugger`] from the current thread.
///
/// After this call, the interpreter runs without any debug checks.  It is
/// safe to call this even if no debugger was attached.
pub fn detach_debugger() {
    ACTIVE_DEBUGGER.with(|d| *d.borrow_mut() = None);
    DEBUG_ATTACHED.with(|f| f.set(false));
}

/// Intern a property key string in the thread-local string table.
///
/// Returns a shared reference-counted handle to the canonical interned copy.
/// Two calls with equal strings return pointer-equal handles, enabling O(1)
/// identity comparison for frequently-used property keys.
pub fn intern_property_key(
    key: &str,
) -> std::sync::Arc<crate::objects::js_string::InternalizedString> {
    STRING_TABLE.with(|table| table.borrow_mut().intern_str(key))
}

/// Returns the number of strings currently interned in the thread-local table.
pub fn interned_string_count() -> usize {
    STRING_TABLE.with(|table| table.borrow().len())
}

/// Reset interpreter thread-local state between test runs.
///
/// Clears the function property side-table and string interning cache so that
/// state from one test execution does not leak into subsequent tests.  Should
/// be called by test harnesses (e.g. Test262) after each test completes.
pub fn clear_interpreter_state() {
    FUNCTION_PROPS.with(|fp| fp.borrow_mut().clear());
    STRING_TABLE.with(|table| {
        *table.borrow_mut() = crate::objects::js_string::StringTable::new();
    });
    REGISTER_POOL.with(|pool| pool.borrow_mut().clear());
    FRAME_POOL.with(|pool| pool.borrow_mut().clear());
    CURRENT_GLOBALS.with(|g| *g.borrow_mut() = None);
    PROTO_CACHE.with(|cache| cache.borrow_mut().clear());
    PROTO_CACHE_GENERATIONS.with(|cache| cache.borrow_mut().clear());
    PROTO_CACHE_EPOCH.with(|epoch| epoch.set(0));
    BUILTIN_METHODS.with(|cache| cache.borrow_mut().clear());
}

/// Look up a built-in constructor by name from the current global environment.
///
/// Used by [`proto_lookup`] to resolve the `"constructor"` property for
/// primitive wrapper types (e.g. `[].constructor === Array`).  Returns
/// [`JsValue::Undefined`] if no global environment is set or the name is
/// not found.
fn lookup_global_constructor(name: &str) -> JsValue {
    CURRENT_GLOBALS.with(|g| {
        g.borrow()
            .as_ref()
            .and_then(|globals| globals.borrow().get(name).cloned())
            .unwrap_or(JsValue::Undefined)
    })
}

fn global_constructor_prototype(name: &str) -> Option<JsValue> {
    match lookup_global_constructor(name) {
        JsValue::PlainObject(map) => map.borrow().get("prototype").cloned(),
        _ => None,
    }
}

fn generator_function_prototype() -> Option<JsValue> {
    global_constructor_prototype("GeneratorFunction")
}

fn async_generator_function_prototype() -> Option<JsValue> {
    global_constructor_prototype("AsyncGeneratorFunction")
}

pub(super) fn default_generator_object_prototype() -> Option<JsValue> {
    generator_function_prototype().and_then(|proto| {
        let value = proto_lookup(&proto, "prototype");
        if matches!(value, JsValue::Undefined) {
            None
        } else {
            Some(value)
        }
    })
}

/// Default prototype for async generator instances:
/// `AsyncGeneratorFunction.prototype.prototype` === `%AsyncGeneratorPrototype%`.
pub(super) fn default_async_generator_object_prototype() -> Option<JsValue> {
    async_generator_function_prototype().and_then(|proto| {
        let value = proto_lookup(&proto, "prototype");
        if matches!(value, JsValue::Undefined) {
            None
        } else {
            Some(value)
        }
    })
}

fn generator_object_prototype(state: &Rc<RefCell<GeneratorState>>) -> Option<JsValue> {
    state.borrow().prototype.clone().or_else(|| {
        if state.borrow().bytecode_array.is_async() {
            default_async_generator_object_prototype()
        } else {
            default_generator_object_prototype()
        }
    })
}

pub(super) fn init_generator_state_prototype(
    state: &Rc<RefCell<GeneratorState>>,
    ba: &Rc<BytecodeArray>,
) {
    let is_async = ba.is_async();
    let prototype = match fn_props_get(ba, "prototype") {
        value @ (JsValue::PlainObject(_) | JsValue::Object(_)) => Some(value),
        _ => {
            if is_async {
                default_async_generator_object_prototype()
            } else {
                default_generator_object_prototype()
            }
        }
    };
    state.borrow_mut().prototype = prototype;
}

/// Return the current thread's active global environment, if any.
pub(crate) fn current_global_env() -> Option<Rc<RefCell<GlobalEnv>>> {
    CURRENT_GLOBALS.with(|g| g.borrow().clone())
}

/// Read a property using the interpreter's ordinary `[[Get]]` semantics.
pub fn dispatch_get_property_value(obj: &JsValue, key: JsValue) -> StatorResult<JsValue> {
    keyed_load(obj, &key)
}

/// Write a property using the interpreter's ordinary `[[Set]]` semantics.
pub fn dispatch_set_property_value(
    obj: &JsValue,
    key: JsValue,
    value: JsValue,
) -> StatorResult<()> {
    keyed_store(obj, &key, value)
}

/// Return the immediate prototype of an object-like value.
pub(crate) fn get_object_prototype(obj: &JsValue) -> Option<JsValue> {
    match obj {
        JsValue::PlainObject(map) => {
            let borrow = map.borrow();
            borrow
                .get(INTERNAL_PROTO_PROPERTY_KEY)
                .or_else(|| borrow.get("__proto__"))
                .cloned()
        }
        JsValue::Promise(promise) => promise.prototype().or_else(|| {
            let ctor = lookup_global_constructor("Promise");
            let proto = proto_lookup(&ctor, "prototype");
            if matches!(proto, JsValue::Undefined) {
                None
            } else {
                Some(proto)
            }
        }),
        JsValue::Error(e) => e
            .props
            .borrow()
            .get(INTERNAL_PROTO_PROPERTY_KEY)
            .cloned()
            .or_else(|| {
                let ctor = lookup_global_constructor(e.kind.as_name());
                let proto = proto_lookup(&ctor, "prototype");
                if matches!(proto, JsValue::Undefined) {
                    None
                } else {
                    Some(proto)
                }
            }),
        _ => None,
    }
}

/// Returns `true` when `map` exposes an own property named `key`.
///
/// Internal accessor slots count as the user-visible property, while the
/// implementation's `__proto__` link does not.
pub(crate) fn plain_object_has_own_property(map: &PropertyMap, key: &str) -> bool {
    key != INTERNAL_PROTO_PROPERTY_KEY
        && (map.contains_key(key) || map.has_getter_for(key) || map.has_setter_for(key))
}

#[inline]
fn is_known_object_prototype_builtin(key: &str) -> bool {
    matches!(
        key,
        "hasOwnProperty"
            | "propertyIsEnumerable"
            | "isPrototypeOf"
            | "constructor"
            | "toString"
            | "valueOf"
            | "toLocaleString"
    )
}

#[inline]
fn refresh_proto_resolution_caches() {
    let epoch = PropertyMap::global_proto_mutation_epoch();
    PROTO_CACHE_EPOCH.with(|cached_epoch| {
        if cached_epoch.get() == epoch {
            return;
        }
        PROTO_CACHE.with(|cache| cache.borrow_mut().clear());
        PROTO_CACHE_GENERATIONS.with(|cache| cache.borrow_mut().clear());
        BUILTIN_METHODS.with(|cache| cache.borrow_mut().clear());
        cached_epoch.set(epoch);
    });
}

#[inline]
fn proto_cache_key(map: &Rc<RefCell<PropertyMap>>, key: &str) -> (usize, u64) {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};
    let mut hasher = DefaultHasher::new();
    key.hash(&mut hasher);
    (Rc::as_ptr(map) as usize, hasher.finish())
}

#[inline]
fn proto_cache_store(
    map: &Rc<RefCell<PropertyMap>>,
    key: &str,
    generation: u32,
    value: &JsValue,
    depth: u8,
) {
    refresh_proto_resolution_caches();
    let cache_key = proto_cache_key(map, key);
    PROTO_CACHE.with(|cache| {
        cache.borrow_mut().insert(cache_key, (value.clone(), depth));
    });
    PROTO_CACHE_GENERATIONS.with(|cache| {
        cache.borrow_mut().insert(cache_key, generation);
    });
}

#[inline]
fn proto_cache_lookup(
    map: &Rc<RefCell<PropertyMap>>,
    key: &str,
    generation: u32,
) -> Option<(JsValue, u8)> {
    refresh_proto_resolution_caches();
    let cache_key = proto_cache_key(map, key);
    let cached_generation =
        PROTO_CACHE_GENERATIONS.with(|cache| cache.borrow().get(&cache_key).copied());
    if cached_generation != Some(generation) {
        if cached_generation.is_some() {
            PROTO_CACHE.with(|cache| {
                cache.borrow_mut().remove(&cache_key);
            });
            PROTO_CACHE_GENERATIONS.with(|cache| {
                cache.borrow_mut().remove(&cache_key);
            });
        }
        return None;
    }
    PROTO_CACHE.with(|cache| cache.borrow().get(&cache_key).cloned())
}

pub(super) fn proto_lookup_cached_resolution(
    map: &Rc<RefCell<PropertyMap>>,
    key: &str,
) -> Option<(JsValue, u8)> {
    let generation = map.borrow().proto_generation();
    proto_cache_lookup(map, key, generation)
}

/// Returns `true` if `key` exists anywhere on `obj`'s prototype chain.
#[allow(dead_code)]
pub(crate) fn has_property_in_chain(obj: &JsValue, key: &str) -> bool {
    let mut current = obj.clone();
    for _ in 0..256 {
        match &current {
            JsValue::PlainObject(map) => {
                let next = {
                    let borrow = map.borrow();
                    if plain_object_has_own_property(&borrow, key) {
                        return true;
                    }
                    borrow.get(INTERNAL_PROTO_PROPERTY_KEY).cloned()
                };
                match next {
                    Some(JsValue::Null) | Some(JsValue::Undefined) => return false,
                    Some(proto) => current = proto,
                    None => {
                        return matches!(
                            key,
                            "hasOwnProperty"
                                | "propertyIsEnumerable"
                                | "isPrototypeOf"
                                | "constructor"
                                | "toString"
                                | "valueOf"
                                | "toLocaleString"
                                | "__lookupGetter__"
                                | "__lookupSetter__"
                                | "__defineGetter__"
                                | "__defineSetter__"
                        );
                    }
                }
            }
            JsValue::Null | JsValue::Undefined => return false,
            _ => return !matches!(proto_lookup(&current, key), JsValue::Undefined),
        }
    }
    false
}

/// Ordinary `[[SetPrototypeOf]]` for `PlainObject`-backed objects.
pub(crate) fn ordinary_set_prototype_of(obj: &JsValue, proto: JsValue) -> StatorResult<()> {
    if !matches!(proto, JsValue::Null) && !proto.is_object_like() {
        return Err(StatorError::TypeError(
            "Object prototype may only be an Object or null".to_string(),
        ));
    }

    let current_proto = get_object_prototype(obj).unwrap_or(JsValue::Null);
    if current_proto.same_value(&proto) {
        return Ok(());
    }

    match obj {
        JsValue::PlainObject(map) => {
            if !map.borrow().extensible {
                return Err(StatorError::TypeError(
                    "Cannot set prototype of a non-extensible object".to_string(),
                ));
            }
            if !matches!(proto, JsValue::Null) && has_prototype_in_chain(&proto, obj) {
                return Err(StatorError::TypeError("Cyclic __proto__ value".to_string()));
            }
            let mut m = map.borrow_mut();
            // Remove legacy "__proto__" key if present so it doesn't
            // shadow the canonical INTERNAL_PROTO_PROPERTY_KEY.
            m.remove("__proto__");
            m.insert(INTERNAL_PROTO_PROPERTY_KEY.to_string(), proto);
        }
        JsValue::Error(e) => {
            if !e.props.borrow().extensible {
                return Err(StatorError::TypeError(
                    "Cannot set prototype of a non-extensible object".to_string(),
                ));
            }
            if !matches!(proto, JsValue::Null) && has_prototype_in_chain(&proto, obj) {
                return Err(StatorError::TypeError("Cyclic __proto__ value".to_string()));
            }
            e.props
                .borrow_mut()
                .insert(INTERNAL_PROTO_PROPERTY_KEY.to_string(), proto);
        }
        _ => {}
    }

    Ok(())
}

/// Return whether `target_proto` appears in `value`'s prototype chain.
pub(crate) fn has_prototype_in_chain(value: &JsValue, target_proto: &JsValue) -> bool {
    let mut current = value.clone();
    for _ in 0..256 {
        let Some(next) = get_object_prototype(&current) else {
            return false;
        };
        if next == *target_proto {
            return true;
        }
        current = next;
    }
    false
}

/// Run `f` with mutable access to the currently-attached [`Debugger`], if
/// any, and return its result wrapped in `Some`.  Returns `None` when no
/// debugger is attached.
///
/// This is a convenience helper for callers that need to query or mutate the
/// debugger after a [`StatorError::DebuggerPaused`] error.
pub fn with_debugger<R, F: FnOnce(&mut Debugger) -> R>(f: F) -> Option<R> {
    ACTIVE_DEBUGGER.with(|d| {
        let opt = d.borrow();
        opt.as_ref().map(|rc| {
            let mut dbg = rc.borrow_mut();
            f(&mut dbg)
        })
    })
}

