/// Sentinel string used by `.return()` to force a return completion through the
/// handler table so that `finally` blocks execute before the generator completes.
pub(super) const GENERATOR_RETURN_SENTINEL: &str = "__stator_generator_return_completion__";
const GENERATOR_RETURN_COMPLETION_MARKER_KEY: &str = "__stator_generator_return_completion__";
const GENERATOR_RETURN_COMPLETION_VALUE_KEY: &str = "value";

#[allow(dead_code)]
pub(crate) fn make_generator_return_completion(value: JsValue) -> JsValue {
    let mut map = PropertyMap::new();
    map.insert(
        GENERATOR_RETURN_COMPLETION_MARKER_KEY.into(),
        JsValue::Boolean(true),
    );
    map.insert(GENERATOR_RETURN_COMPLETION_VALUE_KEY.into(), value);
    JsValue::PlainObject(Rc::new(RefCell::new(map)))
}

pub(crate) fn is_generator_return_completion(value: &JsValue) -> bool {
    matches!(
        value,
        JsValue::PlainObject(map)
            if map
                .borrow()
                .get(GENERATOR_RETURN_COMPLETION_MARKER_KEY)
                .is_some_and(|flag| flag.to_boolean())
    )
}

pub(crate) fn get_generator_return_completion_value(value: &JsValue) -> Option<JsValue> {
    match value {
        JsValue::PlainObject(map) if is_generator_return_completion(value) => map
            .borrow()
            .get(GENERATOR_RETURN_COMPLETION_VALUE_KEY)
            .cloned(),
        _ => None,
    }
}

// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡
// Cross-frame exception propagation
// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

thread_local! {
    /// Holds the original thrown [`JsValue`] when a `Throw`/`ReThrow` opcode
    /// propagates an exception out of a frame as [`StatorError::JsException`].
    ///
    /// The `JsException` variant only carries a stringified message, which
    /// loses the original value.  An outer frame's error handler consumes this
    /// slot to materialise the correct `JsValue` for a `catch` block.
    pub(super) static PENDING_EXCEPTION: RefCell<Option<JsValue>> =
        const { RefCell::new(None) };
}

/// Store a thrown [`JsValue`] so an outer frame can recover it.
pub(super) fn set_pending_exception(val: JsValue) {
    PENDING_EXCEPTION.with(|p| {
        *p.borrow_mut() = Some(val);
    });
}

/// Take the pending thrown [`JsValue`], if any.
pub(super) fn take_pending_exception() -> Option<JsValue> {
    PENDING_EXCEPTION.with(|p| p.borrow_mut().take())
}

// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡
// JIT compilation statistics
// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

thread_local! {
    /// Number of successful baseline JIT compilations in this thread.
    static JIT_COMPILATION_COUNT: Cell<u32> = const { Cell::new(0) };
    /// Total machine-code bytes produced by all successful JIT compilations.
    static JIT_CODE_BYTES: Cell<usize> = const { Cell::new(0) };

    /// Thread-local execution deadline shared by **all** interpreter frames on
    /// this thread.  Unlike the per-frame `deadline` field, this is inherited
    /// automatically by child frames created via `eval()`, `Function()`, etc.
    ///
    /// The interpreter checks this every 100 000 instructions (even when the
    /// per-frame `instruction_limit` is zero) and aborts with a `RangeError`
    /// when the wall-clock time exceeds the deadline.
    static EXECUTION_DEADLINE: Cell<Option<Instant>> = const { Cell::new(None) };
}

// в”Ђв”Ђ Maglev diagnostic counters (per-thread) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
#[cfg(all(target_arch = "x86_64", unix))]
thread_local! {
    /// How many times `try_execute_maglev` was entered (past the deopt guard).
    static MAGLEV_DIAG_TRIED: Cell<u64> = const { Cell::new(0) };
    /// How many times Maglev JIT code ran to completion (no deopt).
    static MAGLEV_DIAG_EXECUTED: Cell<u64> = const { Cell::new(0) };
    /// How many times Maglev JIT code returned `JIT_DEOPT`.
    static MAGLEV_DIAG_DEOPTED: Cell<u64> = const { Cell::new(0) };
    /// Per-category deopt counters: [generic, overflow, stub, global, divzero, unknown].
    static MAGLEV_DIAG_DEOPT_CATS: Cell<[u64; 6]> = const { Cell::new([0; 6]) };
    /// How many times the Maglev cache was empty and background compilation
    /// had not yet delivered code.
    static MAGLEV_DIAG_NOT_READY: Cell<u64> = const { Cell::new(0) };
    /// Flag set while Maglev-generated code is executing, so stubs can
    /// detect context.
    static MAGLEV_EXECUTING: Cell<bool> = const { Cell::new(false) };
    /// How many times `jit_runtime_lda_global` returned `JIT_DEOPT` during
    /// Maglev execution.
    static MAGLEV_DIAG_GLOBAL_DEOPT: Cell<u64> = const { Cell::new(0) };
}

/// Increment the Maglev global-load deopt counter (called from
/// [`jit_runtime_lda_global`] when it returns `JIT_DEOPT`).
#[cfg(all(target_arch = "x86_64", unix))]
pub fn maglev_track_global_deopt() {
    MAGLEV_EXECUTING.with(|f| {
        if f.get() {
            MAGLEV_DIAG_GLOBAL_DEOPT.with(|c| c.set(c.get() + 1));
        }
    });
}

/// Stub for non-JIT platforms.
#[cfg(not(all(target_arch = "x86_64", unix)))]
pub fn maglev_track_global_deopt() {}

/// Set a wall-clock deadline for all interpreter execution on the current
/// thread.  Passing `None` clears any existing deadline.
pub fn set_execution_deadline(deadline: Option<Instant>) {
    EXECUTION_DEADLINE.with(|d| d.set(deadline));
}

/// Return the current thread-local execution deadline, if any.
pub fn get_execution_deadline() -> Option<Instant> {
    EXECUTION_DEADLINE.with(|d| d.get())
}

/// Process-wide count of successful Maglev compilations.
///
/// Uses atomics so the background compilation thread can update the counter
/// while the interpreter thread reads it.
static MAGLEV_COMPILATION_COUNT: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(0);

/// Process-wide total machine-code bytes produced by Maglev compilations.
///
/// Uses atomics so the background compilation thread can update the counter
/// while the interpreter thread reads it.
static MAGLEV_CODE_BYTES: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);

/// Process-wide count of Maglev compilation attempts (threads spawned).
#[cfg(all(target_arch = "x86_64", unix))]
static MAGLEV_COMPILATION_STARTED: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(0);

/// Process-wide count of Maglev compilation failures (graph build or codegen).
#[cfg(all(target_arch = "x86_64", unix))]
static MAGLEV_COMPILATION_FAILED: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(0);

/// Process-wide count of Maglev compilation panics.
#[cfg(all(target_arch = "x86_64", unix))]
static MAGLEV_COMPILATION_PANICKED: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(0);

/// Process-wide count of successful Turbofan compilations.
///
/// Uses atomics so the background compilation thread can update the counter
/// while the interpreter thread reads it.
static TURBOFAN_COMPILATION_COUNT: std::sync::atomic::AtomicU32 =
    std::sync::atomic::AtomicU32::new(0);

/// Process-wide total machine-code bytes produced by Turbofan compilations.
///
/// Uses atomics so the background compilation thread can update the counter
/// while the interpreter thread reads it.
static TURBOFAN_CODE_BYTES: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);

/// Return a snapshot of the JIT compilation statistics for the current thread.
///
/// Returns `(functions_compiled, total_code_bytes)`.
///
/// On platforms where the JIT is not available both values will always be zero.
pub fn jit_stats() -> (u32, usize) {
    (
        JIT_COMPILATION_COUNT.with(|c| c.get()),
        JIT_CODE_BYTES.with(|c| c.get()),
    )
}

/// Return a snapshot of the process-wide Maglev JIT compilation statistics.
///
/// Returns `(functions_compiled, total_code_bytes)`.
///
/// Unlike [`jit_stats`], these counters accumulate across all threads because
/// Maglev compilation runs in background threads.
///
/// On platforms where the JIT is not available both values will always be zero.
pub fn maglev_stats() -> (u32, usize) {
    (
        MAGLEV_COMPILATION_COUNT.load(std::sync::atomic::Ordering::Relaxed),
        MAGLEV_CODE_BYTES.load(std::sync::atomic::Ordering::Relaxed),
    )
}

/// Return a snapshot of the process-wide Turbofan JIT compilation statistics.
///
/// Returns `(functions_compiled, total_code_bytes)`.
///
/// Unlike [`jit_stats`], these counters accumulate across all threads because
/// Turbofan compilation runs in background threads.
///
/// On platforms where the JIT is not available both values will always be zero.
pub fn turbofan_stats() -> (u32, usize) {
    (
        TURBOFAN_COMPILATION_COUNT.load(std::sync::atomic::Ordering::Relaxed),
        TURBOFAN_CODE_BYTES.load(std::sync::atomic::Ordering::Relaxed),
    )
}

/// Return Maglev diagnostic counters for the current thread.
///
/// Returns `(tried, executed, deopted, not_ready, compilations, code_bytes,
/// started, failed, panicked)`.
///
/// On platforms without Maglev JIT support all values are zero.
pub fn maglev_diagnostics() -> (u64, u64, u64, u64, u32, usize, u32, u32, u32) {
    #[cfg(all(target_arch = "x86_64", unix))]
    {
        let tried = MAGLEV_DIAG_TRIED.with(|c| c.get());
        let executed = MAGLEV_DIAG_EXECUTED.with(|c| c.get());
        let deopted = MAGLEV_DIAG_DEOPTED.with(|c| c.get());
        let not_ready = MAGLEV_DIAG_NOT_READY.with(|c| c.get());
        let (compilations, code_bytes) = maglev_stats();
        let started = MAGLEV_COMPILATION_STARTED.load(std::sync::atomic::Ordering::Relaxed);
        let failed = MAGLEV_COMPILATION_FAILED.load(std::sync::atomic::Ordering::Relaxed);
        let panicked = MAGLEV_COMPILATION_PANICKED.load(std::sync::atomic::Ordering::Relaxed);
        return (
            tried,
            executed,
            deopted,
            not_ready,
            compilations,
            code_bytes,
            started,
            failed,
            panicked,
        );
    }
    #[allow(unreachable_code)]
    (0, 0, 0, 0, 0, 0, 0, 0, 0)
}

/// Return per-category deopt counters:
/// `[generic, overflow, stub, global, divzero, unknown]`.
pub fn maglev_deopt_categories() -> [u64; 6] {
    #[cfg(all(target_arch = "x86_64", unix))]
    {
        return MAGLEV_DIAG_DEOPT_CATS.with(|c| c.get());
    }
    #[allow(unreachable_code)]
    [0; 6]
}

/// Return LICM diagnostic counters.
///
/// Returns `(loops_detected, nodes_hoisted, named_generic_hoisted,
/// blocked_by_side_effects)`.
pub fn licm_diagnostics() -> (u32, u32, u32, u32) {
    use crate::compiler::maglev::licm;
    (
        licm::LICM_LOOPS_DETECTED.load(std::sync::atomic::Ordering::Relaxed),
        licm::LICM_NODES_HOISTED.load(std::sync::atomic::Ordering::Relaxed),
        licm::LICM_NAMED_GENERIC_HOISTED.load(std::sync::atomic::Ordering::Relaxed),
        licm::LICM_BLOCKED_BY_SIDE_EFFECTS.load(std::sync::atomic::Ordering::Relaxed),
    )
}

/// Return global promotion diagnostic counters:
/// `(opt_promoted, opt_skipped, codegen_promoted)`.
pub fn globals_promotion_diagnostics() -> (u32, u32, u32) {
    use crate::compiler::maglev::{codegen, optimizer};
    let (promoted, skipped) = optimizer::globals_promoted_diagnostics();
    let cg = codegen::codegen_globals_promoted_count();
    (promoted, skipped, cg)
}

/// Return per-tier compilation counts as `(baseline, maglev, turbofan)`.
pub fn jit_tier_stats() -> (u64, u64, u64) {
    (
        u64::from(JIT_COMPILATION_COUNT.with(|c| c.get())),
        u64::from(MAGLEV_COMPILATION_COUNT.load(std::sync::atomic::Ordering::Relaxed)),
        u64::from(TURBOFAN_COMPILATION_COUNT.load(std::sync::atomic::Ordering::Relaxed)),
    )
}

#[allow(dead_code)]
#[cfg(all(target_arch = "x86_64", unix))]
fn seed_jit_feedback(ba: &BytecodeArray) -> FeedbackVector {
    let mut feedback = ba.feedback_vector_snapshot();
    for slot in 0..ba.feedback_metadata().slot_count() {
        if feedback.get_state(slot) == Some(InlineCacheState::Uninitialized)
            && matches!(
                ba.feedback_metadata().kind_of(slot),
                Some(
                    FeedbackSlotKind::BinaryOp
                        | FeedbackSlotKind::Compare
                        | FeedbackSlotKind::BinaryOpInc
                )
            )
        {
            let _ = feedback.set_state(slot, InlineCacheState::Monomorphic);
        }
    }
    feedback
}

/// Convert a [`JsValue`] to its JIT `i64` representation.
///
/// Primitive types (Smi, Boolean, Undefined, Null) use inline sentinels.
/// All other types (objects, arrays, functions, strings, etc.) are stored
/// in the thread-local heap side-table via [`alloc_jit_heap_handle`] and
/// referenced by handle.  This makes JIT entry infallible for all types.
#[cfg(all(target_arch = "x86_64", unix))]
#[allow(dead_code)]
fn jsvalue_to_jit(v: &JsValue) -> i64 {
    use crate::compiler::baseline::compiler::{
        JIT_FALSE, JIT_NULL, JIT_TRUE, JIT_UNDEFINED, alloc_jit_heap_handle,
    };
    match v {
        JsValue::Smi(n) => *n as i64,
        JsValue::Boolean(b) => {
            if *b {
                JIT_TRUE
            } else {
                JIT_FALSE
            }
        }
        JsValue::Undefined => JIT_UNDEFINED,
        JsValue::Null => JIT_NULL,
        JsValue::HeapNumber(f) => {
            let f = *f;
            if f.fract() == 0.0 && f >= i32::MIN as f64 && f <= i32::MAX as f64 {
                f as i64
            } else {
                alloc_jit_heap_handle(v.clone())
            }
        }
        _ => alloc_jit_heap_handle(v.clone()),
    }
}

/// Request baseline JIT compilation for `ba` and cache the result.
///
/// On supported platforms (x86-64 Unix) this calls [`BaselineCompiler::compile`]
/// and stores the cached executable code via [`BytecodeArray::store_jit_code`].
/// On other platforms this is a no-op.
pub(super) fn maybe_compile_baseline(ba: &BytecodeArray) {
    #[cfg(all(target_arch = "x86_64", unix))]
    {
        use crate::compiler::baseline::compiler::{BaselineCompiler, CachedExecutableCode};
        if let Ok(cc) = BaselineCompiler::compile(ba) {
            let code_len = cc.code.len();
            // SAFETY: `cc.code` was produced by `BaselineCompiler::compile`.
            if let Ok(cached) =
                unsafe { CachedExecutableCode::from_compiled(&cc.code, cc.register_file_slots) }
            {
                ba.store_jit_code(cached);
                JIT_COMPILATION_COUNT.with(|c| c.set(c.get().saturating_add(1)));
                JIT_CODE_BYTES.with(|c| c.set(c.get().saturating_add(code_len)));
            }
        }
    }
    #[cfg(not(all(target_arch = "x86_64", unix)))]
    let _ = ba;
}

/// Build a constant-pool suitable for sending to a background compilation
/// thread.
///
/// [`ConstantPoolEntry::Function`] variants hold a [`BytecodeArray`] that
/// contains `Rc`-based tiering state which is not [`Send`].  For Maglev
/// compilation the inner data of a `Function` entry is never accessed (the
/// graph builder only uses the variant tag to emit an opaque
/// `ConstantPoolEntry` reference node), so we replace the inner
/// [`BytecodeArray`] with a fresh empty one whose `Rc`s are not shared with
/// the main thread.
#[cfg(all(target_arch = "x86_64", unix))]
fn pool_for_compile_thread(pool: &[ConstantPoolEntry]) -> Vec<ConstantPoolEntry> {
    use crate::bytecode::feedback::FeedbackMetadata;
    pool.iter()
        .map(|e: &ConstantPoolEntry| match e {
            ConstantPoolEntry::Function(_) => {
                ConstantPoolEntry::Function(Rc::new(BytecodeArray::new(
                    vec![],
                    vec![],
                    0,
                    0,
                    vec![],
                    FeedbackMetadata::empty(),
                    vec![],
                )))
            }
            other => other.clone(),
        })
        .collect()
}

/// A thin wrapper that marks a [`BytecodeArray`] as safe to transfer to a
/// background compilation thread.
///
/// # Safety
///
/// The wrapped [`BytecodeArray`] must have been freshly constructed (its `Rc`
/// tiering state must not be shared with any other thread), and it must be
/// transferred exclusively to ONE background thread.  No other thread may
/// hold a reference to the same `Rc` instances while the background thread
/// is running.
#[cfg(all(target_arch = "x86_64", unix))]
struct SendableBytecodesArray(BytecodeArray);

// SAFETY: The BytecodeArray wrapped here is freshly constructed with Rc
// instances that are not shared with any other thread.  We guarantee exclusive
// ownership by the background compilation thread.
#[cfg(all(target_arch = "x86_64", unix))]
unsafe impl Send for SendableBytecodesArray {}

#[cfg(all(target_arch = "x86_64", unix))]
impl std::ops::Deref for SendableBytecodesArray {
    type Target = BytecodeArray;
    fn deref(&self) -> &BytecodeArray {
        &self.0
    }
}

/// Compilation input bundle for a Maglev background thread.
///
/// All fields are owned and trivially-`Send`.  The `BytecodeArray` is wrapped
/// in [`SendableBytecodesArray`] which declares exclusive ownership.
#[cfg(all(target_arch = "x86_64", unix))]
struct MaglevCompileInput {
    ba: SendableBytecodesArray,
    result_cache: MaglevJitCodeCache,
}

/// Schedule a Maglev background compilation for `ba`.
///
/// On x86-64 Unix this spawns a background thread that runs the full Maglev
/// pipeline (graph build О“ГҐГ† optimise О“ГҐГ† codegen) and writes the resulting code
/// into `ba`'s Maglev JIT cache.  Subsequent calls will pick up the compiled
/// code via [`BytecodeArray::has_maglev_jit_code`].
///
/// The function is a no-op when:
/// - compilation has already been started (atomic flag check), or
/// - the platform does not support JIT.
pub fn maybe_compile_maglev(ba: &BytecodeArray) {
    #[cfg(all(target_arch = "x86_64", unix))]
    {
        use crate::bytecode::feedback::FeedbackVector;
        use crate::compiler::maglev::codegen as maglev_codegen;
        use crate::compiler::maglev::graph_builder::GraphBuilder;
        use crate::compiler::maglev::optimizer::optimize;

        // NOTE: Top-level scripts are now allowed through to Maglev.
        // The promoted-global prologue/epilogue and speculative Smi guards
        // work well enough for benchmark-style loops.  Baseline JIT is
        // currently disabled (SIGSEGV from unsafe runtime stubs), so
        // Maglev is the only JIT tier available.

        // Only one compilation thread per function.
        if !ba.try_start_maglev_compile() {
            return;
        }

        MAGLEV_COMPILATION_STARTED.fetch_add(1, std::sync::atomic::Ordering::Relaxed);

        let compile_ba = BytecodeArray::new(
            ba.bytecodes().to_vec(),
            pool_for_compile_thread(ba.constant_pool()),
            ba.frame_size(),
            ba.parameter_count(),
            vec![], // source positions not needed for compilation
            ba.feedback_metadata().clone(),
            vec![], // handler table not needed for Maglev graph
        );

        let input = MaglevCompileInput {
            ba: SendableBytecodesArray(compile_ba),
            result_cache: ba.maglev_jit_cache_arc(),
        };

        std::thread::spawn(move || {
            let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                // Access through the SendableBytecodesArray wrapper (Deref) so
                // the Rust 2024 precise closure capture analysis records
                // input.ba (SendableBytecodesArray: Send) not input.ba.0
                // (BytecodeArray: !Send) as the captured variable.
                let feedback = FeedbackVector::new(input.ba.feedback_metadata());
                let param_count = input.ba.parameter_count();
                match GraphBuilder::build(&input.ba, &feedback) {
                    Ok(mut graph) => {
                        optimize(&mut graph);

                        // Skip compilation of degenerate graphs (entry block
                        // immediately deoptimises).  Registering such code would
                        // produce JIT functions that always return JIT_DEOPT,
                        // cascading deoptimisation to callers via Construct /
                        // Call stubs and severely degrading performance.
                        if graph.is_degenerate() {
                            MAGLEV_COMPILATION_FAILED
                                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                        } else {
                            match maglev_codegen::compile(&graph, param_count) {
                                Ok(cc) => {
                                    let code_len = cc.code.len();
                                    if let Ok(mut guard) = input.result_cache.lock() {
                                        // SAFETY: `cc.code` was produced by `maglev_codegen::compile`.
                                        if let Ok(cached) = unsafe {
                                            crate::compiler::baseline::compiler::CachedExecutableCode::from_compiled(
                                            &cc.code,
                                            cc.register_file_slots,
                                        )
                                        } {
                                            *guard = Some(cached);
                                        }
                                        drop(guard);
                                    }
                                    MAGLEV_COMPILATION_COUNT
                                        .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                                    MAGLEV_CODE_BYTES
                                        .fetch_add(code_len, std::sync::atomic::Ordering::Relaxed);
                                }
                                Err(_e) => {
                                    MAGLEV_COMPILATION_FAILED
                                        .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                                }
                            }
                        } // else !is_degenerate
                    }
                    Err(e) => {
                        MAGLEV_COMPILATION_FAILED
                            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                        eprintln!("MAGLEV_COMPILE: graph build failed: {e}");
                    }
                }
            }));
            if let Err(panic) = result {
                MAGLEV_COMPILATION_PANICKED.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                let msg = panic
                    .downcast_ref::<String>()
                    .map(|s| s.as_str())
                    .or_else(|| panic.downcast_ref::<&str>().copied())
                    .unwrap_or("(non-string panic)");
                eprintln!("MAGLEV_COMPILE: thread panicked: {msg}");
            }
        });
    }
    #[cfg(not(all(target_arch = "x86_64", unix)))]
    let _ = ba;
}

/// Try to execute `ba` via the cached Maglev JIT code.
///
/// Returns `Some(result)` when execution succeeds or returns an error;
/// returns `None` when:
/// - Maglev compilation has not finished yet, or
/// - the JIT returns [`JIT_DEOPT`][crate::compiler::baseline::compiler::JIT_DEOPT]
///   (fall-back to the next tier).
///
/// On platforms where the JIT is not available this always returns `None`.
#[allow(dead_code)]
fn try_execute_maglev(_ba: &BytecodeArray, _args: &[JsValue]) -> Option<StatorResult<JsValue>> {
    // Maglev execution is temporarily disabled.  Every sloppy-mode
    // function emits CreateMappedArguments which falls to the
    // unconditional-deopt catch-all in codegen.  The first execution
    // always deopts, but for some programs (closures, constructors,
    // deep chains, keyed stores) the deopt path itself triggers
    // SIGSEGV.  Disabling execution has zero performance impact
    // because the result was always a deopt back to the interpreter.
    // Re-enable once CreateMappedArguments has a proper codegen stub.
    None
}

/// Compilation input bundle for a Turbofan background thread.
///
/// All fields are owned and trivially-`Send`.  The `BytecodeArray` is wrapped
/// in [`SendableBytecodesArray`] which declares exclusive ownership.
#[cfg(all(target_arch = "x86_64", unix))]
struct TurbofanCompileInput {
    ba: SendableBytecodesArray,
    result_cache: TurbofanJitCodeCache,
}

/// Schedule a Turbofan background compilation for `ba`.
///
/// On x86-64 Unix this spawns a background thread that runs the full
/// Turbofan pipeline (graph build в†’ optimise в†’ Cranelift CLIF в†’ native code)
/// and writes the resulting [`TurbofanCompiledCode`] into `ba`'s Turbofan JIT
/// cache.  Subsequent calls will pick up the compiled code via
/// [`BytecodeArray::has_turbofan_jit_code`].
///
/// The function is a no-op when:
/// - compilation has already been started (atomic flag check), or
/// - the platform does not support JIT.
pub(super) fn maybe_compile_turbofan(ba: &BytecodeArray) {
    #[cfg(all(target_arch = "x86_64", unix))]
    {
        use crate::bytecode::feedback::FeedbackVector;
        use crate::compiler::maglev::graph_builder::GraphBuilder;
        use crate::compiler::maglev::optimizer::optimize;
        use crate::compiler::turbofan;

        // NOTE: Top-level scripts are now allowed through to TurboFan
        // (same change as Maglev вЂ” baseline JIT is disabled).

        // Only one compilation thread per function.
        if !ba.try_start_turbofan_compile() {
            return;
        }

        let compile_ba = BytecodeArray::new(
            ba.bytecodes().to_vec(),
            pool_for_compile_thread(ba.constant_pool()),
            ba.frame_size(),
            ba.parameter_count(),
            vec![], // source positions not needed for compilation
            ba.feedback_metadata().clone(),
            vec![], // handler table not needed for Turbofan graph
        );

        let input = TurbofanCompileInput {
            ba: SendableBytecodesArray(compile_ba),
            result_cache: ba.turbofan_jit_cache_arc(),
        };

        std::thread::spawn(move || {
            // Access through the SendableBytecodesArray wrapper (Deref) so the
            // Rust 2024 precise closure capture analysis records input.ba
            // (SendableBytecodesArray: Send) not input.ba.0 (BytecodeArray:
            // !Send) as the captured variable.
            let feedback = FeedbackVector::new(input.ba.feedback_metadata());
            let param_count = input.ba.parameter_count();
            if let Ok(mut graph) = GraphBuilder::build(&input.ba, &feedback) {
                optimize(&mut graph);
                if let Ok(tc) =
                    turbofan::compile_with_feedback(&graph, param_count, Some(&feedback))
                {
                    let code_size = tc.code_size;
                    if let Ok(mut guard) = input.result_cache.lock() {
                        *guard = Some(tc);
                        drop(guard);
                    }
                    // Record Turbofan stats atomically (readable from any thread).
                    TURBOFAN_COMPILATION_COUNT.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    TURBOFAN_CODE_BYTES.fetch_add(code_size, std::sync::atomic::Ordering::Relaxed);
                }
            }
        });
    }
    #[cfg(not(all(target_arch = "x86_64", unix)))]
    let _ = ba;
}

/// Try to execute `ba` via the cached Turbofan JIT code.
///
/// Returns `Some(result)` when execution succeeds or returns an error;
/// returns `None` when:
/// - Turbofan compilation has not finished yet,
/// - one or more arguments cannot be represented in the JIT tier, or
/// - the JIT returns [`JIT_DEOPT`][crate::compiler::baseline::compiler::JIT_DEOPT]
///   (fall-back to the next tier).
///
/// On platforms where the JIT is not available this always returns `None`.
#[allow(dead_code)]
fn try_execute_turbofan(ba: &BytecodeArray, args: &[JsValue]) -> Option<StatorResult<JsValue>> {
    // Turbofan (Cranelift) execution is disabled вЂ” the codegen has bugs in
    // context-slot access and string operations that produce wrong results
    // (e.g. HeapNumber instead of String, wrong Boolean values).
    // Compilation still runs in the background so the code is ready when
    // codegen is fixed.
    let _ = (ba, args);
    None
}

/// Try to execute `ba` via the cached baseline JIT code.
///
/// Returns `Some(result)` when execution succeeds or returns an error;
/// returns `None` when:
/// - no JIT code has been compiled yet,
/// - one or more arguments cannot be represented in the JIT tier, or
/// - the JIT returns [`JIT_DEOPT`][crate::compiler::baseline::compiler::JIT_DEOPT]
///   (fall-back to interpreter).
///
/// On platforms where the JIT is not available this always returns `None`.
fn try_execute_jit(ba: &BytecodeArray, args: &[JsValue]) -> Option<StatorResult<JsValue>> {
    // Baseline JIT execution is disabled вЂ” the runtime stubs added after
    // ab83085 contain unsafe aliasing / unchecked-index bugs that cause
    // SIGSEGV on Linux.  Maglev is the only active JIT tier.
    let _ = (ba, args);
    None
}

/// Try to execute `ba` via the fastest available JIT tier.
///
/// Checks Turbofan first (highest tier), then Maglev, then falls back to
/// baseline JIT.  Returns `None` if no tier has compiled code ready.
pub(super) fn try_execute_best_jit(
    ba: &BytecodeArray,
    args: &[JsValue],
) -> Option<StatorResult<JsValue>> {
    // Never run JIT when a debugger is attached вЂ” the debugger needs
    // to single-step through interpreted bytecodes.
    if DEBUG_ATTACHED.with(|f| f.get()) {
        return None;
    }
    // Try Turbofan first (highest tier вЂ” Cranelift native code).
    if let Some(r) = try_execute_turbofan(ba, args) {
        return Some(r);
    }
    // Then Maglev (register-allocated JIT).
    if let Some(r) = try_execute_maglev(ba, args) {
        return Some(r);
    }
    // Baseline JIT (disabled вЂ” SIGSEGV from unsafe runtime stubs).
    try_execute_jit(ba, args)
}

// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡
// MegamorphicIc О“Г‡Гґ shape-based inline cache with fixed-size direct-mapped table
// О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

/// Number of entries in the megamorphic inline-cache table.
///
/// A power-of-two size allows cheap modular indexing via bitmask.  64 entries
/// provide good coverage for megamorphic call-sites while staying within two
/// cache lines per probe.
const MEGAMORPHIC_IC_SIZE: usize = 64;

/// A single inline-cache entry that maps a `(feedback_slot, layout_id)` pair
/// to a direct slot offset inside a [`PropertyMap`], enabling O(1) property
/// access across objects that share the same layout.
///
/// When `is_proto` is set, the property lives on the receiver's immediate
/// prototype rather than on the receiver itself, and `proto_layout` records
/// the prototype's layout so the hit can be validated in constant time.
#[derive(Debug, Clone, Copy)]
pub struct MegamorphicIcEntry {
    /// Feedback slot this entry was populated from (tag for collision check).
    pub slot: u32,
    /// The `layout_id` of the receiver when the cache was populated.
    pub receiver_layout: u64,
    /// The `Vec` offset of the cached property inside the target
    /// [`PropertyMap`].
    pub cached_offset: u16,
    /// `true` when the property was found on the receiver's direct `__proto__`
    /// rather than on the receiver itself.
    pub is_proto: bool,
    /// When `is_proto`, the `layout_id` of the prototype that owns the
    /// property.  Ignored when `is_proto` is `false`.
    pub proto_layout: u64,
}

impl Default for MegamorphicIcEntry {
    fn default() -> Self {
        Self {
            slot: u32::MAX,
            receiver_layout: 0,
            cached_offset: 0,
            is_proto: false,
            proto_layout: 0,
        }
    }
}

/// Fixed-size, direct-mapped megamorphic inline cache for named property
/// access.
///
/// Entries are indexed by `feedback_slot & (MEGAMORPHIC_IC_SIZE - 1)`.
/// Collisions are resolved by overwrite, providing natural LRU-ish eviction
/// that works well for megamorphic sites where many different shapes compete
/// for the same feedback slot.
#[derive(Debug, Clone)]
pub struct MegamorphicIc {
    entries: Box<[MegamorphicIcEntry; MEGAMORPHIC_IC_SIZE]>,
}

impl MegamorphicIc {
    /// Creates a new empty megamorphic IC table.
    fn new() -> Self {
        Self {
            entries: Box::new([MegamorphicIcEntry::default(); MEGAMORPHIC_IC_SIZE]),
        }
    }

    /// Probes the cache for a `(slot, receiver_layout)` pair.
    #[inline]
    pub fn probe(&self, slot: u32, receiver_layout: u64) -> Option<&MegamorphicIcEntry> {
        let idx = (slot as usize) & (MEGAMORPHIC_IC_SIZE - 1);
        let entry = &self.entries[idx];
        if entry.slot == slot && entry.receiver_layout == receiver_layout {
            Some(entry)
        } else {
            None
        }
    }

    /// Inserts or overwrites the entry for the given feedback slot.
    #[inline]
    pub fn update(&mut self, entry: MegamorphicIcEntry) {
        let idx = (entry.slot as usize) & (MEGAMORPHIC_IC_SIZE - 1);
        self.entries[idx] = entry;
    }
}

/// Cached result for a prototype-chain property load.
///
/// Stores the value found by walking the prototype chain, guarded by the
/// receiver's layout and the prototype-chain generation counter.  When both
/// match, the cached value can be returned without re-walking the chain.
#[derive(Debug, Clone)]
pub struct ProtoLoadIc {
    /// Feedback slot this entry belongs to (used for direct-mapped indexing).
    pub slot: u32,
    /// Prototype-chain generation snapshot for the receiver.
    pub proto_generation: u32,
    /// Receiver layout observed when the cache entry was populated.
    pub receiver_shape: u64,
    /// Global prototype-mutation epoch snapshot taken when this entry was
    /// populated.  When the current epoch still matches, no prototype in
    /// the entire runtime has been mutated, so `proto_generation` is
    /// guaranteed valid and need not be recomputed.
    pub proto_global_epoch: u64,
    /// Value returned by the inherited property lookup.
    pub value: JsValue,
}

impl Default for ProtoLoadIc {
    fn default() -> Self {
        Self {
            slot: u32::MAX,
            receiver_shape: 0,
            proto_generation: 0,
            proto_global_epoch: u64::MAX,
            value: JsValue::Undefined,
        }
    }
}

const PROTO_IC_SIZE: usize = 32;

#[derive(Debug, Clone)]
/// Fixed-size direct-mapped cache for prototype-chain IC entries.
///
/// Uses `slot & (PROTO_IC_SIZE - 1)` as index, matching the `MegamorphicIc`
/// design for O(1) lookup without hashing overhead.
pub struct ProtoIcCache {
    entries: Box<[ProtoLoadIc; PROTO_IC_SIZE]>,
}

impl Default for ProtoIcCache {
    fn default() -> Self {
        Self::new()
    }
}

impl ProtoIcCache {
    /// Creates an empty cache with all sentinel entries.
    pub fn new() -> Self {
        Self {
            entries: Box::new(std::array::from_fn(|_| ProtoLoadIc::default())),
        }
    }

    /// Probes for a cached entry matching `slot` and `receiver_layout`.
    #[inline(always)]
    pub fn probe(&self, slot: u32, receiver_layout: u64) -> Option<&ProtoLoadIc> {
        let idx = (slot as usize) & (PROTO_IC_SIZE - 1);
        let entry = &self.entries[idx];
        if entry.slot == slot && entry.receiver_shape == receiver_layout {
            Some(entry)
        } else {
            None
        }
    }

    /// Fast-path probe guarded by the global prototype-mutation epoch.
    ///
    /// When the epoch matches, no prototype anywhere in the runtime has
    /// been mutated since the entry was populated, so the cached
    /// `proto_generation` is guaranteed valid and `proto_generation()`
    /// need not be called at all.
    #[inline(always)]
    pub fn probe_epoch(
        &self,
        slot: u32,
        receiver_layout: u64,
        global_epoch: u64,
    ) -> Option<&ProtoLoadIc> {
        let idx = (slot as usize) & (PROTO_IC_SIZE - 1);
        // SAFETY: PROTO_IC_SIZE is a power of two so the mask is always
        // in bounds.
        let entry = unsafe { self.entries.get_unchecked(idx) };
        if entry.slot == slot
            && entry.proto_global_epoch == global_epoch
            && entry.receiver_shape == receiver_layout
        {
            Some(entry)
        } else {
            None
        }
    }

    /// Inserts or overwrites the entry for the given slot.
    pub fn update(&mut self, ic: ProtoLoadIc) {
        let idx = (ic.slot as usize) & (PROTO_IC_SIZE - 1);
        self.entries[idx] = ic;
    }

    /// Evicts the entry for `slot` (sets it back to the sentinel).
    pub fn remove(&mut self, slot: u32) {
        let idx = (slot as usize) & (PROTO_IC_SIZE - 1);
        if self.entries[idx].slot == slot {
            self.entries[idx] = ProtoLoadIc::default();
        }
    }
}

/// Small inline-buffered argument storage for interpreter function calls.
pub type CallArgs = SmallVec<[JsValue; 4]>;

/// Register files with up to this many slots stay inline in the frame.
/// 16 slots (384 bytes) covers the vast majority of closures and small
/// functions while keeping `InterpreterFrame` compact.  Larger register
/// files spill to the thread-local register pool.
pub const SMALL_REG_THRESHOLD: usize = 24;

/// Inline-buffered register storage for interpreter frames.
pub type RegisterFile = SmallVec<[JsValue; SMALL_REG_THRESHOLD]>;

/// Direct-mapped global variable cache: 8 entries of (name_hash, name, value).
type GlobalCacheArray = [(u64, Option<Rc<str>>, JsValue); 8];

/// Acquire a register file from the pool, or allocate a new one.
fn acquire_registers(count: usize) -> RegisterFile {
    if count <= SMALL_REG_THRESHOLD {
        let mut regs = RegisterFile::new();
        regs.resize(count, JsValue::Undefined);
        return regs;
    }

    REGISTER_POOL.with(|pool| {
        let mut pool = pool.borrow_mut();
        if let Some(pos) = pool.iter().position(|regs| regs.capacity() >= count) {
            let mut regs = pool.swap_remove(pos);
            regs.clear();
            regs.resize(count, JsValue::Undefined);
            RegisterFile::from_vec(regs)
        } else {
            RegisterFile::from_vec(vec![JsValue::Undefined; count])
        }
    })
}

/// Return a register file to the pool for reuse.
fn release_registers(regs: RegisterFile) {
    if regs.spilled() {
        let mut regs = regs.into_vec();
        regs.clear();
        REGISTER_POOL.with(|pool| {
            let mut pool = pool.borrow_mut();
            if pool.len() < 16 {
                pool.push(regs);
            }
        });
    }
}

/// Maximum number of [`InterpreterFrame`] structs kept in the thread-local pool.
const FRAME_POOL_CAP: usize = 16;

/// Acquire an [`InterpreterFrame`] from the thread-local pool, or allocate a
/// new one.  When a pooled frame is available its fields are reset in-place,
/// avoiding a fresh heap allocation for the register file, IC caches, and
/// other per-frame state.
#[inline]
pub(super) fn acquire_frame(
    bytecode_array: Rc<BytecodeArray>,
    args: impl IntoIterator<Item = JsValue>,
    global_env: Rc<RefCell<GlobalEnv>>,
) -> InterpreterFrame {
    let maybe_frame = FRAME_POOL.with(|pool| pool.borrow_mut().pop());

    if let Some(mut frame) = maybe_frame {
        let args: CallArgs = args.into_iter().collect();
        let param_count = bytecode_array.parameter_count() as usize;
        let frame_size = bytecode_array.frame_size() as usize;
        let total_regs = param_count + frame_size;

        // Reuse the register buffer via the register pool.
        release_registers(std::mem::take(&mut frame.registers));
        frame.registers = acquire_registers(total_regs);
        for (i, arg) in args.iter().cloned().enumerate().take(param_count) {
            frame.registers[i] = arg;
        }

        frame.bytecode_array = bytecode_array;
        frame.call_args = args;
        frame.accumulator = JsValue::Undefined;
        frame.pc = 0;
        frame.context = None;
        frame.suspend_result = None;
        frame.generator_state = None;
        frame.global_env = global_env;
        frame.osr_loop_count = 0;
        frame.instruction_limit = 0;
        frame.instructions_executed = 0;
        frame.deadline = None;
        frame.pending_message = JsValue::Undefined;
        frame.new_target = JsValue::Undefined;
        // IC caches are lazily allocated О“Г‡Г¶ reset to None.
        frame.mono_load_cache = None;
        frame.poly_load_cache = None;
        frame.mega_load_ic = None;
        frame.proto_load_ic = None;
        frame.mega_store_ic = None;
        frame.string_cache = None;
        frame.global_ic = None;
        frame.global_cache = None;
        frame.cache_generation = 0;
        frame.smi_mode = false;
        frame.hot_registers = None;
        frame.loop_end_pc = 0;
        frame.loop_trip_counts.clear();
        return frame;
    }

    // No pooled frame available О“Г‡Г¶ allocate a new one.
    InterpreterFrame::new_callee_frame(bytecode_array, args, global_env)
}

/// Return an [`InterpreterFrame`] to the thread-local pool for reuse.
///
/// All `JsValue` fields are cleared to prevent reference leaks.  The frame's
/// register buffer has already been returned to `REGISTER_POOL` by
/// [`Interpreter::run_inner`], so we do not touch it here.
#[inline]
fn release_frame(mut frame: InterpreterFrame) {
    // Clear all JsValue / Rc fields to allow them to be dropped.
    frame.accumulator = JsValue::Undefined;
    frame.context = None;
    frame.call_args.clear();
    frame.pending_message = JsValue::Undefined;
    frame.new_target = JsValue::Undefined;
    frame.suspend_result = None;
    frame.generator_state = None;
    // Drop remaining IC caches О“Г‡Г¶ they were already written back to
    // the BytecodeArray in run_inner.
    frame.mono_load_cache = None;
    frame.poly_load_cache = None;
    frame.mega_load_ic = None;
    frame.proto_load_ic = None;
    frame.mega_store_ic = None;
    frame.string_cache = None;
    frame.global_ic = None;
    frame.global_cache = None;
    frame.hot_registers = None;
    frame.loop_trip_counts.clear();

    FRAME_POOL.with(|pool| {
        let mut pool = pool.borrow_mut();
        if pool.len() < FRAME_POOL_CAP {
            pool.push(frame);
        }
        // else: drop the frame, releasing its memory
    });
}

