    // О“Г¶Г‡О“Г¶Г‡ Star / Ldar О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

    #[test]
    fn test_star_ldar_round_trip() {
        // lda 7 О“ГҐГ† r0, lda 0, ldar r0 О“ГҐГ† return 7
        let result = run_bytecode(
            vec![
                Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(7)]),
                Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(0)]),
                Instruction::new_unchecked(Opcode::LdaZero, vec![]),
                Instruction::new_unchecked(Opcode::Ldar, vec![Operand::Register(0)]),
                Instruction::new_unchecked(Opcode::Return, vec![]),
            ],
            1,
        )
        .unwrap();
        assert_eq!(result, JsValue::Smi(7));
    }

    // О“Г¶Г‡О“Г¶Г‡ Arithmetic О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

    /// Helper: evaluate `lhs <op> rhs` using the standard Ignition pattern:
    /// evaluate rhs О“ГҐГ† r0, evaluate lhs О“ГҐГ† acc, apply op.
    fn arith_op(lhs: i32, rhs: i32, op: Opcode) -> StatorResult<JsValue> {
        run_bytecode(
            vec![
                // Save rhs to r0
                Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(rhs)]),
                Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(0)]),
                // Load lhs into acc
                Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(lhs)]),
                // acc = acc <op> r0
                Instruction::new_unchecked(
                    op,
                    vec![Operand::Register(0), Operand::FeedbackSlot(0)],
                ),
                Instruction::new_unchecked(Opcode::Return, vec![]),
            ],
            1, // one local register (r0)
        )
    }

    #[test]
    fn test_add_integers() {
        assert_eq!(arith_op(3, 4, Opcode::Add).unwrap(), JsValue::Smi(7));
        assert_eq!(arith_op(0, 0, Opcode::Add).unwrap(), JsValue::Smi(0));
        assert_eq!(arith_op(-5, 5, Opcode::Add).unwrap(), JsValue::Smi(0));
        assert_eq!(arith_op(100, 200, Opcode::Add).unwrap(), JsValue::Smi(300));
    }

    #[test]
    fn test_concat_rc_strs_reuses_empty_operand() {
        let empty: Rc<str> = Rc::from("");
        let text: Rc<str> = Rc::from("hello");

        let left_empty = concat_rc_strs(&empty, &text);
        let right_empty = concat_rc_strs(&text, &empty);

        let JsValue::String(left_empty) = left_empty else {
            panic!("expected string result");
        };
        let JsValue::String(right_empty) = right_empty else {
            panic!("expected string result");
        };

        assert!(Rc::ptr_eq(&left_empty, &text));
        assert!(Rc::ptr_eq(&right_empty, &text));
    }

    #[test]
    fn test_js_add_fast_path_concatenates_strings() {
        let lhs = JsValue::String(Rc::from("foo"));
        let rhs = JsValue::String(Rc::from("bar"));

        assert_eq!(
            js_add(&lhs, &rhs).unwrap(),
            JsValue::String(Rc::from("foobar"))
        );
    }

    #[test]
    fn test_sub_integers() {
        assert_eq!(arith_op(10, 3, Opcode::Sub).unwrap(), JsValue::Smi(7));
        assert_eq!(arith_op(0, 5, Opcode::Sub).unwrap(), JsValue::Smi(-5));
    }

    #[test]
    fn test_mul_integers() {
        assert_eq!(arith_op(6, 7, Opcode::Mul).unwrap(), JsValue::Smi(42));
        assert_eq!(arith_op(0, 999, Opcode::Mul).unwrap(), JsValue::Smi(0));
        assert_eq!(arith_op(-3, 4, Opcode::Mul).unwrap(), JsValue::Smi(-12));
    }

    #[test]
    fn test_div_integers() {
        // 10 / 2 = 5 (exact О“ГҐГ† Smi)
        assert_eq!(arith_op(10, 2, Opcode::Div).unwrap(), JsValue::Smi(5));
        // 7 / 2 = 3.5 (fractional О“ГҐГ† HeapNumber)
        assert_eq!(
            arith_op(7, 2, Opcode::Div).unwrap(),
            JsValue::HeapNumber(3.5)
        );
    }

    #[test]
    fn test_div_by_zero() {
        // JS: 1 / 0 = Infinity
        let result = arith_op(1, 0, Opcode::Div).unwrap();
        assert_eq!(result, JsValue::HeapNumber(f64::INFINITY));
    }

    #[test]
    fn test_smi_mode_lda_global_shift_left_and_bitwise_not() {
        let pool = vec![ConstantPoolEntry::String("value".to_string())];
        let instrs = vec![
            Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(1)]),
            Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(0)]),
            Instruction::new_unchecked(
                Opcode::LdaGlobal,
                vec![Operand::ConstantPoolIdx(0), Operand::FeedbackSlot(0)],
            ),
            Instruction::new_unchecked(
                Opcode::ShiftLeft,
                vec![Operand::Register(0), Operand::FeedbackSlot(1)],
            ),
            Instruction::new_unchecked(Opcode::BitwiseNot, vec![Operand::FeedbackSlot(2)]),
            Instruction::new_unchecked(Opcode::Return, vec![]),
        ];

        let (result, frame) =
            run_smi_mode_bytecode_with_globals(instrs, pool, 1, &[("value", JsValue::Smi(3))])
                .unwrap();

        assert_eq!(result, JsValue::Smi(-7));
        // smi_mode is cleared when the SMI loop hits an unsupported
        // opcode (Return) О“Г‡Г¶ checking the result is sufficient.
        let _ = frame;
    }

    #[test]
    fn test_smi_mode_bitwise_xor_and_shift_right_logical() {
        let pool = vec![ConstantPoolEntry::String("value".to_string())];
        let instrs = vec![
            Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(1)]),
            Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(0)]),
            Instruction::new_unchecked(
                Opcode::LdaGlobal,
                vec![Operand::ConstantPoolIdx(0), Operand::FeedbackSlot(0)],
            ),
            Instruction::new_unchecked(
                Opcode::BitwiseXor,
                vec![Operand::Register(0), Operand::FeedbackSlot(1)],
            ),
            Instruction::new_unchecked(
                Opcode::ShiftRightLogical,
                vec![Operand::Register(0), Operand::FeedbackSlot(2)],
            ),
            Instruction::new_unchecked(Opcode::Return, vec![]),
        ];

        let (result, frame) =
            run_smi_mode_bytecode_with_globals(instrs, pool, 1, &[("value", JsValue::Smi(10))])
                .unwrap();

        assert_eq!(result, JsValue::Smi(5));
        // smi_mode is cleared when the SMI loop hits an unsupported
        // opcode (Return) О“Г‡Г¶ checking the result is sufficient.
        let _ = frame;
    }

    fn run_forced_smi_loop_bytecode(
        instrs: Vec<Instruction>,
        frame_size: u32,
        registers: &[(u32, JsValue)],
    ) -> StatorResult<JsValue> {
        let loop_end_pc = instrs.len().saturating_sub(1);
        let ba = make_bytecode(instrs, frame_size, 0);
        let mut frame = InterpreterFrame::new(Rc::new(ba), vec![]);
        for (reg, value) in registers {
            unsafe { frame.write_reg_unchecked(*reg, value.clone()) };
        }
        frame.smi_mode = true;
        frame.loop_end_pc = loop_end_pc;
        frame.accumulator = JsValue::Smi(0);
        frame.hot_registers = Some(HotRegisters::new(frame.registers.len()));
        Interpreter::run(&mut frame)
    }

    #[test]
    fn test_smi_mode_call_undefined_receiver2_reenters_on_smi_result() {
        let add = Rc::new(make_add_bytecode());
        let instrs = vec![
            Instruction::new_unchecked(
                Opcode::CallUndefinedReceiver2,
                vec![
                    Operand::Register(0),
                    Operand::Register(1),
                    Operand::Register(2),
                    Operand::FeedbackSlot(0),
                ],
            ),
            Instruction::new_unchecked(
                Opcode::AddSmi,
                vec![Operand::Immediate(1), Operand::FeedbackSlot(1)],
            ),
            Instruction::new_unchecked(Opcode::Return, vec![]),
        ];

        let result = run_forced_smi_loop_bytecode(
            instrs,
            3,
            &[
                (0, JsValue::Function(add)),
                (1, JsValue::Smi(3)),
                (2, JsValue::Smi(4)),
            ],
        )
        .unwrap();

        assert_eq!(result, JsValue::Smi(8));
    }

