    #[test]
    fn test_named_property_ic_reuses_shared_layout_across_objects() {
        use crate::bytecode::feedback::{FeedbackMetadata, FeedbackSlotKind};
        let instrs = vec![
            Instruction::new_unchecked(Opcode::CreateEmptyObjectLiteral, vec![]),
            Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(0)]),
            Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(11)]),
            Instruction::new_unchecked(
                Opcode::StaNamedProperty,
                vec![
                    Operand::Register(0),
                    Operand::ConstantPoolIdx(0),
                    Operand::FeedbackSlot(0),
                ],
            ),
            Instruction::new_unchecked(Opcode::CreateEmptyObjectLiteral, vec![]),
            Instruction::new_unchecked(Opcode::Star, vec![Operand::Register(1)]),
            Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(22)]),
            Instruction::new_unchecked(
                Opcode::StaNamedProperty,
                vec![
                    Operand::Register(1),
                    Operand::ConstantPoolIdx(0),
                    Operand::FeedbackSlot(0),
                ],
            ),
            Instruction::new_unchecked(
                Opcode::LdaNamedProperty,
                vec![
                    Operand::Register(0),
                    Operand::ConstantPoolIdx(0),
                    Operand::FeedbackSlot(1),
                ],
            ),
            Instruction::new_unchecked(
                Opcode::LdaNamedProperty,
                vec![
                    Operand::Register(1),
                    Operand::ConstantPoolIdx(0),
                    Operand::FeedbackSlot(1),
                ],
            ),
            Instruction::new_unchecked(Opcode::Return, vec![]),
        ];
        let ba = BytecodeArray::new(
            encode(&instrs),
            vec![ConstantPoolEntry::String("x".to_string())],
            2,
            0,
            vec![],
            FeedbackMetadata::new(vec![
                FeedbackSlotKind::StoreProperty,
                FeedbackSlotKind::LoadProperty,
            ]),
            vec![],
        );
        let mut frame = InterpreterFrame::new(Rc::new(ba), vec![]);
        let result = Interpreter::run(&mut frame).unwrap();
        // Both objects have property "x"; the last LdaNamedProperty loads from
        // register 1 (which holds 22), so the result must be Smi(22).
        assert_eq!(result, JsValue::Smi(22));
        // Note: frame.registers is empty after run() because registers are
        // released back to the thread-local pool. We can only verify the
        // return value and IC metadata here.
    }

    // О“Г¶Г‡О“Г¶Г‡ StaLookupSlot О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

