    // О“Г¶Г‡О“Г¶Г‡ JumpIfJSReceiver О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

    #[test]
    fn test_jump_if_js_receiver_object_jumps() {
        // Byte layout:
        //   [0] CreateEmptyObjectLiteral О“ГҐГ† 1 byte
        //   [1] JumpIfJSReceiver(2)      О“ГҐГ† 2 bytes, end=3, target=3+2=5
        //   [3] LdaSmi(0)               О“ГҐГ† 2 bytes О“ГҐГ‰ skipped
        //   [5] Return                  О“ГҐГ† 1 byte
        let ba = make_bytecode_with_pool(
            vec![
                Instruction::new_unchecked(Opcode::CreateEmptyObjectLiteral, vec![]),
                Instruction::new_unchecked(Opcode::JumpIfJSReceiver, vec![Operand::JumpOffset(2)]),
                Instruction::new_unchecked(Opcode::LdaSmi, vec![Operand::Immediate(0)]),
                Instruction::new_unchecked(Opcode::Return, vec![]),
            ],
            vec![],
            0,
            0,
        );
        let mut frame = InterpreterFrame::new(Rc::new(ba), vec![]);
        let result = Interpreter::run(&mut frame).unwrap();
        assert!(matches!(result, JsValue::PlainObject(_)));
    }

