    /// Compile a JavaScript source string and run it through the interpreter.
    fn compile_source_and_run(src: &str) -> StatorResult<JsValue> {
        use crate::bytecode::bytecode_generator::BytecodeGenerator;
        let program = crate::parser::recursive_descent::parse(src)?;
        let ba = BytecodeGenerator::compile_program(&program)?;
        let mut frame = InterpreterFrame::new(Rc::new(ba), vec![]);
        Interpreter::run(&mut frame)
    }

    fn assert_script_result(src: &str, expected: JsValue) {
        let result = compile_source_and_run(src).unwrap();
        assert_eq!(result, expected, "script: {src}");
    }

    fn assert_script_syntax_error(src: &str) {
        let err = compile_source_and_run(src).unwrap_err();
        assert!(matches!(err, StatorError::SyntaxError(_)), "{src}: {err:?}");
    }

