    // О“Г¶Г‡О“Г¶Г‡ Array.prototype.includes О“Г‡Г¶ SameValueZero О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡О“Г¶Г‡

    #[test]
    fn test_array_includes_nan() {
        // SameValueZero: NaN is equal to NaN
        let result = crate::builtins::global::global_eval("[NaN].includes(NaN)").unwrap();
        assert_eq!(result, JsValue::Boolean(true));
    }

    #[test]
